INSERT INTO dawah_questions (category_id, slug, title, short_answer, detailed_answer, evidences, glossary_terms, sources, keywords, target_religion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'sikh-guru-granth-islamic-view',
'أنا سيخي/سيخية — كيف يرى الإسلام عقيدة السيخية في الإله الواحد والمعلّمين العشرة؟',
'تشترك السيخية مع الإسلام في توحيد الإله (Ik Onkar) ورفض الأصنام والوساطة الكهنوتية، لكنها تختلف في اعتبار "غورو غرانث صاحب" (الكتاب المقدَّس) مُعلِّمًا حيًا خالدًا خلفًا لعشرة معلّمين بشريين (غورو)؛ يرى الإسلام أن الوحي الحق توقف بخاتم الأنبياء محمد ﷺ.',
'تأسست السيخية على يد المعلّم ناناك في القرن الخامس عشر بإقليم البنجاب، وتقوم عقيدتها المركزية على توحيد إله واحد (يُعبَّر عنه بعبارة "إك أونكار") لا شريك له، ورفض الطبقية الطائفية الهندوسية الصارمة، والدعوة للمساواة وخدمة الآخرين. من الملاحظ أن هذا التوحيد يجعل السيخية أقرب فلسفيًا لبعض الأديان التوحيدية من الأديان الهندية التعددية. تتميز السيخية بخلافة عشرة معلّمين بشريين (غورو) توارثوا القيادة الروحية، وينتهي هذا التسلسل باعتبار الكتاب المقدَّس نفسه ("غورو غرانث صاحب") المعلّم الحي الخالد الأخير الذي يُرجَع إليه بدل معلّم بشري بعد الغورو العاشر. يحترم الإسلام مبدأ توحيد الإله المشترك هنا، ويوافق على رفض الوساطة الكهنوتية والطبقية الظالمة كقيم مشتركة. الفارق الجوهري: يرى الإسلام أن الوحي الإلهي الحقيقي توقف بخاتم الأنبياء محمد ﷺ، وأن أي "تعليم" لاحق مهما بلغ سموه الأخلاقي لا يحمل صفة الوحي الإلهي المعصوم، بخلاف تصور استمرارية الهداية عبر سلسلة المعلّمين في السيخية. هذا اختلاف عقدي جوهري يستحق حوارًا مباشرًا مع داعية مطّلع على الخلفية السيخية تحديدًا.',
'[{"type":"quran","ref":"الأحزاب: ٤٠","text":"وَلَٰكِن رَّسُولَ اللَّهِ وَخَاتَمَ النَّبِيِّينَ"}]'::jsonb,
'[{"term":"غورو","definition":"لقب المعلّم الروحي في السيخية؛ توارثه عشرة معلّمين بشريين قبل أن يُنسَب اللقب للكتاب المقدَّس نفسه."}]'::jsonb,
'[]'::jsonb,
ARRAY['السيخية','التوحيد','خاتم الأنبياء'], 'sikh', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'jain-no-creator-god-islamic-view',
'أنا جايني/جاينية ولا أومن بإله خالق — كيف يخاطبني الإسلام؟',
'تعلّم الجاينية أن الكون أزلي غير مخلوق تحكمه قوانين طبيعية ثابتة (الكارما)، والخلاص يتحقق بجهد فردي صارم أساسه اللاعنف المطلق (أهimsa) تجاه كل كائن حي؛ يقدّم الإسلام تصورًا مختلفًا جذريًا: كون مخلوق بإرادة خالق واحد رحيم، والخلاص علاقة مع هذا الخالق لا جهدًا فرديًا منعزلًا فقط.',
'الجاينية ديانة هندية قديمة جدًا، نُظِّمت تعاليمها على يد المعلّم ماهافيرا (القرن السادس قبل الميلاد تقريبًا، آخر "تيرثانكارا" أي معلّم عابر في سلسلة أربعة وعشرين معلّمًا). من أبرز خصائصها العقدية عدم وجود إله خالق في التصور الجايني الكلاسيكي: يُعتقَد أن الكون أزلي غير مخلوق، تحكمه قوانين طبيعية ثابتة أهمها قانون الكارما (نتيجة حتمية لكل فعل تلاحق الروح عبر دورات إعادة الميلاد). الخصيصة الأشهر عالميًا للجاينية هي التزامها الصارم جدًا بمبدأ "أهimsa" (اللاعنف المطلق) تجاه كل كائن حي مهما صغر، حتى أن الرهبان الجاينيين قد يكسحون الأرض أمامهم لتجنب دهس حشرة عن غير قصد، والنباتية الصارمة جدًا واجب ديني مركزي. الخلاص (موكشا) يتحقق بجهد فردي منضبط عبر "الجواهر الثلاثة" (الإيمان الصحيح، المعرفة الصحيحة، السلوك الصحيح) لتحرير الروح من دورة الكارما، لا بعلاقة مع كائن أعلى يُعبَد. يقدّم الإسلام تصورًا مختلفًا جذريًا في نقطتين مركزيتين: الكون مخلوق بإرادة خالق واحد حكيم رحيم لا أزلي بذاته، والخلاص علاقة مباشرة حية بهذا الخالق (عبادة ودعاء وتوبة) لا جهدًا فرديًا معزولًا عن أي كائن أعلى. مع ذلك، يشترك الإسلام مع الجاينية في تقدير الرحمة بالمخلوقات كقيمة أخلاقية مهمة، وإن اختلف مستوى الإلزام وأساسه الفلسفي جذريًا.',
'[]'::jsonb,
'[{"term":"أهimسا","definition":"مبدأ اللاعنف المطلق تجاه كل كائن حي، من أبرز الخصائص العقدية للجاينية."}, {"term":"موكشا","definition":"التحرر النهائي للروح من دورة الكارما وإعادة الميلاد في الفلسفات الهندية."}]'::jsonb,
'[]'::jsonb,
ARRAY['الجاينية','اللاعنف','الكارما'], 'jain', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'zoroastrian-dualism-islamic-view',
'أنا زرادشتي/زرادشتية — كيف يرى الإسلام ثنائية الخير والشر عند أهورامزدا؟',
'تؤمن الزرادشتية بإله واحد أعلى (أهورامزدا) يمثّل الخير والنور، في صراع كوني مع قوة شريرة (أنجرا مينيو)، والنار رمز مقدَّس لنور أهورامزدا لا معبود بذاتها؛ يرى الإسلام توحيدًا مطلقًا لا ثنائية فيه: الله وحده خالق كل شيء، خيره وشره الظاهري جزء من حكمته الشاملة لا صراعًا بين قوتين متكافئتين.',
'الزرادشتية ديانة فارسية قديمة جدًا نُسبت لتعاليم النبي زرادشت (زرادشت)، ويُعامَل أتباعها في الفقه الإسلامي التاريخي معاملة قريبة من أهل الكتاب في بعض الأحكام (كأخذ الجزية) رغم الخلاف الفقهي حول انطباق وصف "أهل الكتاب" عليهم بدقة. تقوم عقيدتها المركزية على إله أعلى واحد يُدعى "أهورامزدا" يمثّل الخير والنور والحق المطلق، في مواجهة كونية مستمرة مع قوة معاكسة تُدعى "أنجرا مينيو" (أو أهريمان) تمثّل الشر والظلام والكذب، ويُطلَب من الإنسان الانحياز للخير عبر "الفكر الحسن، والقول الحسن، والعمل الحسن". النار رمز مقدَّس عند الزرادشتيين لنور أهورامزدا وطهارته، وتُحفَظ مشتعلة في معابدهم كرمز لا كمعبود بذاتها كما يُظَن أحيانًا خطأً. يختلف الإسلام هنا في نقطة جوهرية: التوحيد المطلق بلا أي ثنائية أو منازع لله في الخلق أو التدبير — كل ما يحدث، خيره وشره الظاهري، يقع بإذن الله وحكمته الشاملة، لا نتيجة صراع فعلي بين قوتين متكافئتين في القدرة كما في التصور الثنائي. هذا لا يعني تسطيح مسألة الخير والشر (وقد فُصِّلت في مادة مستقلة عن "مشكلة الشر")، بل رفض فكرة وجود قوة شريرة مستقلة تُضاهي قدرة الله ذاتها.',
'[{"type":"quran","ref":"الزمر: ٦٢","text":"اللَّهُ خَالِقُ كُلِّ شَيْءٍ"}]'::jsonb,
'[{"term":"أهورامزدا","definition":"الإله الأعلى في الزرادشتية، ممثّل الخير والنور والحق المطلق."}]'::jsonb,
'[]'::jsonb,
ARRAY['الزرادشتية','ثنائية الخير والشر','التوحيد'], 'zoroastrian', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'bahai-progressive-revelation-islamic-view',
'أنا بهائي/بهائية — لماذا لا يقبل الإسلام فكرة استمرار الوحي بعد محمد ﷺ؟',
'تؤمن البهائية بأن الوحي الإلهي "متدرّج" مستمر عبر مظاهر إلهية متعاقبة (منها إبراهيم وموسى وعيسى ومحمد وبهاء الله)، بينما يقرر الإسلام صراحة أن محمدًا ﷺ خاتم الأنبياء والمرسلين، وأن أي دعوى نبوة أو وحي جديد بعده مخالفة صريحة لنص قرآني قطعي، وهذا الفارق هو جوهر اعتبار علماء المسلمين البهائية دينًا مستقلًا خارج الإسلام لا مذهبًا داخله.',
'نشأت البهائية في القرن التاسع عشر في سياق فارسي متصل بالحركة البابية، على يد بهاء الله. من عقائدها المركزية مفهوم "الوحي المتدرّج" (Progressive Revelation): الله يرسل عبر التاريخ "مظاهر إلهية" متعاقبة (يُعَدّ منها إبراهيم وموسى وبوذا وكريشنا وزرادشت وعيسى ومحمد ثم بهاء الله) كل واحد منهم يحمل رسالة تناسب عصره ضمن تطور تدريجي مستمر للوحي الإلهي، وبهاء الله في هذا التصور هو "المظهر" الأحدث لا الأخير بالضرورة. تدعو البهائية أيضًا لوحدة الأديان والبشرية كقيمة مركزية. هنا يقع الفارق العقدي الجوهري والمباشر مع الإسلام: يقرر القرآن نصًا صريحًا قطعي الدلالة أن محمدًا ﷺ "خاتم النبيين"، أي آخرهم على الإطلاق، وأن باب الوحي والنبوة أُغلِق نهائيًا بعده. أي دعوى نبوة أو وحي إلهي جديد بعد محمد ﷺ، مهما بلغت سماحة تعاليمها الأخلاقية الظاهرة، تُناقِض هذا النص القطعي مباشرة. لهذا السبب تحديدًا اعتبر علماء المسلمين المعتبرون البهائية دينًا مستقلًا خارج نطاق الإسلام تمامًا، لا مذهبًا أو فرقة داخله، رغم أن جذورها التاريخية نشأت في سياق إسلامي-شيعي.',
'[{"type":"quran","ref":"الأحزاب: ٤٠","text":"مَّا كَانَ مُحَمَّدٌ أَبَا أَحَدٍ مِّن رِّجَالِكُمْ وَلَٰكِن رَّسُولَ اللَّهِ وَخَاتَمَ النَّبِيِّينَ"}]'::jsonb,
'[{"term":"المظهر الإلهي","definition":"مصطلح بهائي يشير إلى الأنبياء ومؤسسي الأديان الكبرى بصفتهم تجليات متعاقبة للإرادة الإلهية عبر التاريخ."}]'::jsonb,
'[]'::jsonb,
ARRAY['البهائية','خاتم الأنبياء','الوحي المتدرج'], 'bahai', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'chinese-tradition-tian-dao-islamic-view',
'أتبع تقاليد صينية (كونفوشيوسية/طاوية) — كيف يرى الإسلام مفهوم "تيان" و"الطاو"؟',
'تجمع التقاليد الصينية بين عناصر فلسفية أخلاقية (الكونفوشيوسية: الانسجام الاجتماعي وبرّ الوالدين)، وتأمل في "الطاو" (الطريق/المبدأ الطبيعي الكوني الطاوي)، وتوقير "تيان" (السماء) وتكريم الأسلاف — وهي غالبًا أقرب لمنظومة أخلاقية-فلسفية-روحية متكاملة منها إلى دين توحيدي بمعنى إله شخصي خالق كما في الإسلام.',
'من الأمانة العلمية أولًا الإقرار بأن "التقاليد الصينية" ليست دينًا واحدًا موحَّدًا، بل نسيجًا معقدًا من عناصر متداخلة عبر تاريخ طويل جدًا: الكونفوشيوسية (تعاليم أخلاقية-فلسفية اجتماعية أسسها كونفوشيوس، تركّز على الانسجام الاجتماعي، وبرّ الوالدين، وأخلاق "الرجل النبيل"، وتوقير "تيان" أي السماء كمصدر نظام أخلاقي كوني، مع توقير الأسلاف كممارسة مركزية)، والطاوية (فلسفية وروحية، تتأمل في "الطاو" أي الطريق أو المبدأ الطبيعي الأزلي الذي يسري في كل الكون، مع مبدأ التوازن بين المتضادات "يين ويانغ"، والدعوة لـ"اللافعل" أي الانسجام مع مجرى الطبيعة بدل مقاومته)، إضافة لعناصر دينية شعبية تتضمن تعدد آلهة وأرواح محلية في بعض الممارسات الشعبية. هذا المزيج غالبًا أقرب لمنظومة أخلاقية-فلسفية-روحية متكاملة الأبعاد منها لدين توحيدي بالمعنى الإبراهيمي الدقيق (إله شخصي خالق يُعبَد ويُدعى مباشرة). يقدّم الإسلام تصورًا مختلفًا محدَّدًا بوضوح: إله واحد شخصي خالق حكيم يُعبَد ويُدعى مباشرة اسمه الله، لا مبدأً كونيًا مجردًا (كالطاو) ولا سماءً رمزية (كتيان) ولا تكريم أسلاف كممارسة دينية. مع ذلك، يشترك الإسلام مع هذه التقاليد في تقدير القيم الأخلاقية كبرّ الوالدين والانسجام الاجتماعي كقيم أصيلة، وإن اختلف أساسها الفلسفي واللاهوتي جذريًا.',
'[]'::jsonb,
'[{"term":"الطاو","definition":"المبدأ أو الطريق الطبيعي الأزلي الذي يسري في كل الكون في الفلسفة الطاوية الصينية."}, {"term":"تيان","definition":"مفهوم \"السماء\" في الفكر الصيني التقليدي، مصدر النظام الأخلاقي الكوني عند كونفوشيوس."}]'::jsonb,
'[]'::jsonb,
ARRAY['التقاليد الصينية','الطاوية','الكونفوشيوسية'], 'chinese_folk', 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'secular-humanism-vs-islam',
'أنا ملحد/ملحدة أومن بالإنسانية العلمانية — لماذا أحتاج دينًا أصلًا لأكون شخصًا صالحًا؟',
'الإنسانية العلمانية تبني الأخلاق على توافق إنساني عقلاني بلا مرجعية متعالية، وهذا قد ينتج التزامًا أخلاقيًا حقيقيًا فعليًا، لكن الإسلام يطرح سؤالًا أعمق: هل يملك هذا الالتزام أساسًا ثابتًا يصمد أمام اختلاف المجتمعات والعصور، أم أنه في النهاية تفضيل جماعي قابل للتغير الجذري بتغير التوافق نفسه؟',
'الإنسانية العلمانية (Secular Humanism) منظومة أخلاقية وفلسفية جادة تبني القيم الأخلاقية على العقل والتعاطف الإنساني والتوافق الاجتماعي، بلا حاجة لمرجعية إلهية متعالية، وتؤكد كرامة الإنسان وحقوقه كأساس كافٍ للأخلاق. يقرّ الإسلام بأن كثيرًا من أتباع هذا التصور يعيشون فعلًا حياة أخلاقية ملتزمة، وأن العقل الإنساني السليم يستطيع فعلًا إدراك كثير من القيم الأخلاقية الكبرى (كالعدل وتحريم الظلم) دون وحي مباشر، وهذا ما يُعرَف في الفقه الإسلامي بـ"التحسين والتقبيح العقلي" الجزئي. لكن السؤال الفلسفي الأعمق الذي يطرحه الإسلام: على أي أساس نهائي تُبنى إلزامية هذه القيم إن كانت في النهاية "توافقًا إنسانيًا" محضًا؟ التوافق الإنساني تاريخيًا تغيّر جذريًا بين مجتمعات وعصور مختلفة حول قضايا أخلاقية جوهرية (كالعبودية التي كانت "أخلاقية" بتوافق مجتمعات كاملة لقرون)، فما الذي يمنع تغيّرًا مماثلًا مستقبلًا لقيم يُعَدّ اليوم انتهاكها فظيعًا؟ الإسلام يقدّم مرجعية أخلاقية ثابتة لا تخضع لتقلّب التوافق الاجتماعي عبر الزمن، وهذا فارق فلسفي جوهري يستحق تأملًا صادقًا بصرف النظر عن مدى التزامك الأخلاقي الفعلي الحالي، والذي لا يُشكّك فيه الإسلام إطلاقًا.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['الإنسانية العلمانية','الإلحاد','أساس الأخلاق'], 'atheist_agnostic', 'draft', false)
ON CONFLICT (slug) DO NOTHING;
